  import sailpoint.object.Identity;
  import sailpoint.tools.Util;

  import sailpoint.api.IdentityService;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Application;
  import sailpoint.object.Link;
  import sailpoint.object.Bundle;
  

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("Ascension-Rule-Library-Amita-BirthrightAssignment");
  
  /**
	 * get the assignmentCriteria value of the input role and convert in map
	 * @param roleName : input role name
	 * @return Map : contains bundle criteria details
	 * @throws GeneralException
   * DeptMin=67073|DeptMax=67073|Loc=ILARL257|Job=901140
	 */
  public Map getBundleCriteria(String roleName) {
		String methodName = "getBundleCriteria";
		logger.debug("Entering" + methodName);
    
    Map result = new HashMap();
		String input = "";
		
		try {
			Bundle role = context.getObjectByName(Bundle.class, roleName);
			if (role != null){
				if(role.getAttribute("assignmentCriteria") != null ) {
					input = role.getAttribute("assignmentCriteria").toString();
					if(Util.isNotNullOrEmpty(input)){
						String []inputsplit = input.split("\\|");
						String []subStrSplit;
						if (inputsplit != null && inputsplit.length > 0) {
							for (String subStr : inputsplit) {
								subStrSplit = subStr.split("=");
								if (subStrSplit != null && subStrSplit.length > 0) {
									if (subStrSplit.length > 1 && Util.isNotNullOrEmpty(subStrSplit[1])) {
										result.put(subStrSplit[0].trim(), subStrSplit[1].trim());
									} else {
										result.put(subStrSplit[0].trim(), "");
									}
								}
							}
						}
					}
				}
				//comment decache //context.decache(role);
			}
		} catch (Exception ex) {
			logger.error("Exception in getBundleCreteria " + ex.getMessage());
		}
		logger.debug("Exiting " + methodName);
		return result;
	}
  
  /**
	 * check the eligibility of identity based on given input value
	 * @param identityName : identity,inputJobCodeToken : bundle jobcode, inputLocationToken : bundle location, inputMinDepartmentNumberToken : bundle department
	 * @return boolean : true when satisfy the condition
	 * @throws GeneralException
   * DeptMin=67073|DeptMax=67073|Loc=ILARL257|Job=901140
	 */ 

  public boolean isEligibleAmitaBundleAssignment(String identityName,String inputJobCodeToken,String inputLocationToken,String inputMinDepartmentNumberToken,String inputMaxDepartmentNumberToken){
    logger.debug("isEligibleAmitaBundleAssignment Starting");
    boolean isEligibleIdentity = false;
    boolean isValidDept = false;
    boolean isValidLocation = false;
    boolean isValidJobCode = false;

    Identity identity = context.getObjectByName(Identity.class,identityName);
    if(identity!=null){

      String departmentNumber = identity.getStringAttribute("departmentNumber");
      String location = identity.getStringAttribute("buildingId");
      String jobCode = identity.getStringAttribute("jobcode");
      String domain = identity.getStringAttribute("domain");

      String inputJobCode = inputJobCodeToken;
      String inputLocation = inputLocationToken;
      String inputMinDepartmentNumber = inputMinDepartmentNumberToken;
      String inputMaxDepartmentNumber = inputMaxDepartmentNumberToken;

      //Attributes from Secondary Peoplesoft account
      String departmentNumberFromSA = null;
      String locationFromSA = null;
      String jobCodeFromSA = null;


      if(Util.nullSafeCaseInsensitiveEq(domain , "AMITA") ){

        Application application = (Application) context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Secondary");
        if(application !=null ) {
          IdentityService identityService = new IdentityService(context);
          List links = Util.filterNulls(identityService.getLinks(identity, application));
          if(!Util.isEmpty(links)){
            for (Object object : links) {
              Link link = (Link) object;
              if(link!=null){
                departmentNumberFromSA = (String) link.getAttribute("DEPTID");
                locationFromSA = (String) link.getAttribute("LOCATION");
                jobCodeFromSA = (String) link.getAttribute("JOBCODE");
              }
            }
          }
          //comment decache //context.decache(application);
        }
        

        if(!(Util.isNullOrEmpty(inputJobCode) && Util.isNullOrEmpty(inputLocation) && Util.isNullOrEmpty(inputMinDepartmentNumber) && Util.isNullOrEmpty(inputMaxDepartmentNumber)) ){

          if((Util.isNotNullOrEmpty(departmentNumber) || Util.isNotNullOrEmpty(departmentNumberFromSA)) && Util.isNotNullOrEmpty(inputMinDepartmentNumber) && Util.isNotNullOrEmpty(inputMaxDepartmentNumber)){
            try {
              int inputMinDeptNo = Integer.parseInt(inputMinDepartmentNumber);
              int inputMaxDeptNo = Integer.parseInt(inputMaxDepartmentNumber);
              int deptNo = 0;
              if(Util.isNotNullOrEmpty(departmentNumber)){
                deptNo = Integer.parseInt(departmentNumber);
              }
              int deptNoSA = 0;
              if(Util.isNotNullOrEmpty(departmentNumberFromSA)){
                deptNoSA = Integer.parseInt(departmentNumberFromSA);
              }

              if((deptNo <= inputMaxDeptNo && deptNo >= inputMinDeptNo) || (deptNoSA <= inputMaxDeptNo && deptNoSA >= inputMinDeptNo)){
                isValidDept = true;
              }	
            } catch (NumberFormatException e) {
              isValidDept = false;
            }
          }else if(Util.isNullOrEmpty(inputMinDepartmentNumber) && Util.isNullOrEmpty(inputMaxDepartmentNumber)){
            isValidDept = true;
          }
          

          if(isValidDept && ((Util.nullSafeCaseInsensitiveEq(location, inputLocation) || Util.nullSafeCaseInsensitiveEq(locationFromSA, inputLocation)) || Util.isNullOrEmpty(inputLocation))){
            isValidLocation = true;
          }
          if(isValidLocation && isValidDept && ((Util.nullSafeCaseInsensitiveEq(jobCode , inputJobCode) || Util.nullSafeCaseInsensitiveEq(jobCodeFromSA , inputJobCode)) || Util.isNullOrEmpty(inputJobCode))){
            isValidJobCode = true;
          }
          if(isValidDept && isValidJobCode && isValidLocation){
            isEligibleIdentity =  true;
          }
        }
      }
     
    }
    logger.debug("isEligibleAmitaBundleAssignment Ending");
    return isEligibleIdentity;
  }
